import type { Metadata } from "next"

import { company, programs, deriveKpis } from "./data"
import { SubsidyMatchingConsole } from "./SubsidyMatchingConsole"

// Server Component shell. The pure helpers in ./data (deriveKpis / formatYenShort)
// have NO function props and live outside the "use client" boundary, so calling
// them here on the server is safe. The interactive console (state, FilterChips,
// Leaderboard onSelect, MatchDetail render) lives in a "use client" child.
export function generateMetadata(): Metadata {
  const kpis = deriveKpis(programs)
  return {
    title: `補助金ナビ｜${company.name}のマッチング`,
    description: `${company.name}（${company.industry}）に適合する補助金・助成金 ${kpis.matchedCount}件。申請可能 ${kpis.applicableCount}件。`,
  }
}

export default function SubsidyMatchingPage() {
  return (
    <main className="min-h-screen bg-background text-foreground">
      <SubsidyMatchingConsole />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  IconBuildingFactory2,
  IconCertificate,
  IconCheck,
  IconAlertTriangle,
  IconX,
  IconStarFilled,
  IconUserCheck,
  IconExternalLink,
  IconFileText,
} from "@tabler/icons-react"
import {
  Card,
  Badge,
  Button,
  Meter,
  MetadataList,
  Separator,
} from "@gunjo/ui"

import {
  type CompanyProfile,
  type SubsidyProgram,
  type MatchRequirement,
  type RequirementMatch,
  formatYenShort,
} from "./data"

/**
 * MatchDetail — 自社（企業）× 補助金制度 の「マッチ詳細」。
 *
 * ⚠️ ハンドロール。@gunjo/ui には二項のペアリング primitive が
 * `RelationshipRow` しか無く、それは PersonCell 固定（人 ⟷ 人）。
 * ここは「企業（自社）× 制度（補助金）」という *異種* の対なので使えない。
 * 左右の identity ブロック・適合度コネクタ・要件突き合わせ表を自前で組む。
 */

const MATCH_META: Record<
  RequirementMatch,
  { glyph: string; label: string; Icon: typeof IconCheck; tone: string; ring: string }
> = {
  excellent: { glyph: "◎", label: "加点", Icon: IconStarFilled, tone: "text-success", ring: "bg-success-subtle text-success-subtle-foreground border-success-border" },
  ok: { glyph: "○", label: "適合", Icon: IconCheck, tone: "text-success", ring: "bg-success-subtle text-success-subtle-foreground border-success-border" },
  review: { glyph: "△", label: "要確認", Icon: IconAlertTriangle, tone: "text-warning", ring: "bg-warning-subtle text-warning-subtle-foreground border-warning-border" },
  fail: { glyph: "×", label: "不適合", Icon: IconX, tone: "text-destructive", ring: "bg-destructive-subtle text-destructive-subtle-foreground border-destructive-border" },
}

function MatchJudgement({ match }: { match: RequirementMatch }) {
  const m = MATCH_META[match]
  return (
    <span
      className={`inline-flex h-6 min-w-6 items-center justify-center gap-1 rounded-full border px-2 text-xs font-semibold ${m.ring}`}
    >
      <span aria-hidden className="text-sm leading-none">
        {m.glyph}
      </span>
      <span className="sr-only">{m.label}</span>
      <span aria-hidden>{m.label}</span>
    </span>
  )
}

/** 左右どちらかの identity ブロック（自前の "EntityCell"）。 */
function EntityHeader({
  icon,
  eyebrow,
  title,
  lines,
  accent,
}: {
  icon: React.ReactNode
  eyebrow: string
  title: string
  lines: string[]
  accent: string
}) {
  return (
    <div className="flex min-w-0 items-start gap-3">
      <div
        className={`flex size-10 shrink-0 items-center justify-center rounded-lg ${accent}`}
        aria-hidden
      >
        {icon}
      </div>
      <div className="min-w-0">
        <p className="text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">
          {eyebrow}
        </p>
        <p className="truncate text-sm font-semibold text-foreground" title={title}>
          {title}
        </p>
        {lines.map((l, i) => (
          <p key={i} className="truncate text-xs text-muted-foreground" title={l}>
            {l}
          </p>
        ))}
      </div>
    </div>
  )
}

export function MatchDetail({
  company,
  program,
}: {
  company: CompanyProfile
  program: SubsidyProgram
}) {
  const fitTone =
    program.fitScore >= 80 ? "success" : program.fitScore >= 60 ? "primary" : "warning"
  const blocking = program.requirements.filter((r) => r.match === "fail")
  const bonusCount = program.requirements.filter((r) => r.match === "excellent").length

  return (
    <Card className="overflow-hidden">
      {/* ── 二者ヘッダー（自社 × 制度） ── */}
      <div className="grid grid-cols-1 gap-3 p-4 sm:grid-cols-[1fr_auto_1fr] sm:items-center sm:gap-2">
        <EntityHeader
          icon={<IconBuildingFactory2 className="size-5 text-info" />}
          eyebrow="自社"
          title={company.name}
          lines={[`${company.industry}・従業員${company.employees}名`, company.location]}
          accent="bg-info-subtle"
        />

        {/* コネクタ＋適合度 */}
        <div
          className="flex shrink-0 flex-row items-center justify-center gap-2 sm:flex-col sm:gap-1"
          aria-hidden
        >
          <span className="text-xs font-medium text-muted-foreground">適合度</span>
          <span
            className={`text-2xl font-bold tabular-nums leading-none ${
              fitTone === "success" ? "text-success" : fitTone === "warning" ? "text-warning" : "text-primary"
            }`}
          >
            {program.fitScore}
            <span className="text-sm font-medium text-muted-foreground"> %</span>
          </span>
        </div>

        <EntityHeader
          icon={<IconCertificate className="size-5 text-primary" />}
          eyebrow={`補助金制度 ・ ${program.authority}`}
          title={program.name}
          lines={[`${program.kind}・${program.purpose}`, `補助上限 ${formatYenShort(program.maxAmount)}（補助率 ${program.subsidyRate}）`]}
          accent="bg-primary/10"
        />
      </div>

      {/* 適合度メーター（SR向けに適合度の数値を読み上げ） */}
      <div className="px-4 pb-2">
        <Meter
          value={program.fitScore}
          max={100}
          direction="higher-is-better"
          target={70}
          tone={fitTone === "success" ? "success" : fitTone === "warning" ? "warning" : "primary"}
          label={`${company.name} と ${program.name} の適合度`}
          unit="%"
          size="sm"
        />
      </div>

      <Separator />

      {/* ── サマリ＋推定受給額 ── */}
      <div className="flex flex-col gap-3 p-4">
        <p className="text-sm text-foreground">{program.summary}</p>
        <MetadataList
          layout="horizontal"
          variant="compact"
          items={[
            { label: "推定受給額", value: program.estimatedGrant > 0 ? formatYenShort(program.estimatedGrant) : "対象外の可能性" },
            { label: "補助上限 / 下限", value: program.minAmount ? `${formatYenShort(program.maxAmount)} / ${formatYenShort(program.minAmount)}` : formatYenShort(program.maxAmount) },
            { label: "採択率", value: `${Math.round(program.adoptionRate * 100)}%（直近 ${program.adoptedCount.toLocaleString("ja-JP")}件）` },
            { label: "申請期限", value: program.daysLeft >= 999 ? "通年（随時）" : `${program.deadline}（残り${program.daysLeft}日）` },
          ]}
        />
        {bonusCount > 0 && (
          <div className="flex flex-wrap items-center gap-1.5">
            <span className="text-xs font-medium text-muted-foreground">加点項目</span>
            {program.bonusPoints.map((b) => (
              <Badge key={b} variant="success" icon={<IconStarFilled />}>
                {b}
              </Badge>
            ))}
          </div>
        )}
        {blocking.length > 0 && (
          <div className="flex items-start gap-2 rounded-md border border-destructive-border bg-destructive-subtle px-3 py-2 text-sm text-destructive-subtle-foreground">
            <IconAlertTriangle className="mt-0.5 size-4 shrink-0 text-destructive" aria-hidden />
            <span>
              申請前に解消が必要：
              {blocking.map((b) => b.label).join("・")}
            </span>
          </div>
        )}
      </div>

      <Separator />

      {/* ── 要件ごとの突き合わせ（自社 ↔ 制度） ── */}
      <div className="p-4">
        <h3 className="mb-3 text-sm font-semibold text-foreground">
          要件の突き合わせ
          <span className="ml-2 text-xs font-normal text-muted-foreground">
            自社の実態 ↔ 制度の要件
          </span>
        </h3>

        {/* 列ヘッダー（≥sm で表組み風、モバイルは積み上げ） */}
        <div className="hidden grid-cols-[1fr_1fr_auto] gap-3 border-b border-border pb-1.5 sm:grid">
          <span className="text-[11px] font-semibold uppercase tracking-wide text-info">自社</span>
          <span className="text-[11px] font-semibold uppercase tracking-wide text-primary">制度の要件</span>
          <span className="text-right text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">判定</span>
        </div>

        <ul role="list" className="divide-y divide-border">
          {program.requirements.map((req: MatchRequirement, i) => (
            <li key={i} className="py-3">
              <div className="mb-1 flex items-center justify-between gap-2 sm:hidden">
                <span className="text-sm font-medium text-foreground">{req.label}</span>
                <MatchJudgement match={req.match} />
              </div>
              <div className="grid grid-cols-1 gap-x-3 gap-y-1.5 sm:grid-cols-[1fr_1fr_auto] sm:items-start">
                <span className="hidden text-sm font-medium text-foreground sm:col-span-3 sm:block">
                  {req.label}
                  {req.isBonus && (
                    <span className="ml-2 align-middle text-[11px] font-semibold text-success">
                      加点項目
                    </span>
                  )}
                </span>
                <div className="min-w-0 rounded-md bg-info-subtle/40 px-2.5 py-1.5">
                  <span className="text-[10px] font-medium uppercase text-info sm:hidden">自社</span>
                  <p className="text-sm text-foreground">{req.companyValue}</p>
                </div>
                <div className="min-w-0 rounded-md bg-muted px-2.5 py-1.5">
                  <span className="text-[10px] font-medium uppercase text-primary sm:hidden">制度</span>
                  <p className="text-sm text-foreground">{req.programValue}</p>
                </div>
                <div className="hidden self-center sm:block">
                  <MatchJudgement match={req.match} />
                </div>
              </div>
              {req.note && (
                <p className="mt-1.5 text-xs text-muted-foreground">※ {req.note}</p>
              )}
            </li>
          ))}
        </ul>
      </div>

      <Separator />

      {/* ── アクション ── */}
      <div className="flex flex-col gap-2 p-4 sm:flex-row sm:flex-wrap sm:items-center">
        <Button
          variant={blocking.length > 0 ? "outline" : "primary"}
          disabled={blocking.length > 0}
          className="w-full sm:w-auto"
        >
          <IconFileText className="size-4" aria-hidden />
          {blocking.length > 0 ? "申請（要件未充足）" : "申請する"}
        </Button>
        <Button variant="outline" className="w-full sm:w-auto">
          <IconExternalLink className="size-4" aria-hidden />
          公募要領の詳細を見る
        </Button>
        <Button variant="ghost" className="w-full sm:w-auto">
          <IconUserCheck className="size-4" aria-hidden />
          専門家に相談する
        </Button>
      </div>
    </Card>
  )
}

"use client"

import * as React from "react"
import {
  IconBuildingFactory2,
  IconTargetArrow,
  IconClockExclamation,
  IconCoin,
  IconCircleCheck,
  IconId,
  IconFileText,
  IconCalendarDue,
} from "@tabler/icons-react"
import {
  PageHeader,
  StatGroup,
  Leaderboard,
  type LeaderboardItem,
  FilterChips,
  ActionQueue,
  type ActionItem,
  Badge,
  MetadataList,
  Card,
  Separator,
} from "@gunjo/ui"

import {
  company,
  programs as allPrograms,
  formatYenShort,
  deriveKpis,
  type SubsidyProgram,
} from "./data"
import { MatchDetail } from "./MatchDetail"

type PurposeFilter = "all" | SubsidyProgram["purpose"]
type KindFilter = "all" | SubsidyProgram["kind"]

export function SubsidyMatchingConsole() {
  const [kind, setKind] = React.useState<KindFilter>("all")
  const [purpose, setPurpose] = React.useState<PurposeFilter>("all")
  const [selectedId, setSelectedId] = React.useState<string>(allPrograms[0].id)

  const filtered = React.useMemo(
    () =>
      allPrograms
        .filter((p) => (kind === "all" ? true : p.kind === kind))
        .filter((p) => (purpose === "all" ? true : p.purpose === purpose))
        .slice()
        .sort((a, b) => b.fitScore - a.fitScore),
    [kind, purpose]
  )

  // 選択中の制度が絞り込みから外れたら、先頭にフォールバック。
  React.useEffect(() => {
    if (filtered.length > 0 && !filtered.some((p) => p.id === selectedId)) {
      setSelectedId(filtered[0].id)
    }
  }, [filtered, selectedId])

  const selected =
    allPrograms.find((p) => p.id === selectedId) ?? filtered[0] ?? allPrograms[0]
  const kpis = deriveKpis(allPrograms)

  // ── ランキング（適合度順）─ Leaderboard items ──
  const leaderboardItems: LeaderboardItem[] = filtered.map((p) => ({
    id: p.id,
    label: p.name,
    sublabel: `${p.kind}・補助上限 ${formatYenShort(p.maxAmount)}・補助率 ${p.subsidyRate}・採択率 ${Math.round(
      p.adoptionRate * 100
    )}%`,
    value: p.fitScore,
    valueLabel: `${p.fitScore}%`,
    tone: p.fitScore >= 80 ? "success" : p.fitScore >= 60 ? "primary" : "warning",
    trailing: (
      <Badge
        variant={p.daysLeft <= 14 ? "warning" : "outline"}
        icon={p.daysLeft <= 14 ? <IconClockExclamation /> : undefined}
      >
        {p.daysLeft >= 999 ? "通年" : `残り${p.daysLeft}日`}
      </Badge>
    ),
    onSelect: () => setSelectedId(p.id),
  }))

  // ── 要対応・締切キュー ──
  const queueItems: ActionItem[] = [
    {
      id: "gbiz",
      severity: "critical",
      kind: "電子申請",
      title: "gBizIDプライムが未取得です",
      detail: "IT導入補助金など電子申請にはgBizIDプライムが必須。取得に2〜3週間かかります。",
      meta: "申請前に必須",
    },
    {
      id: "it-deadline",
      severity: "critical",
      kind: "締切間近",
      title: "IT導入補助金（通常枠）の締切まで残り5日",
      detail: "登録ITツールの最終選定と交付申請の準備を進めてください。",
      meta: "2026/7/18 締切",
    },
    {
      id: "mono-deadline",
      severity: "warning",
      kind: "締切間近",
      title: "ものづくり補助金の締切まで残り9日",
      detail: "事業計画書・見積書（CNC旋盤）の最終確認を。最有力案件です。",
      meta: "2026/8/22 締切",
    },
    {
      id: "docs",
      severity: "warning",
      kind: "書類準備",
      title: "事業継続力強化計画の認定書を添付してください",
      detail: "ものづくり補助金の加点に必要。認定書の写しを準備します。",
      meta: "加点項目",
    },
    {
      id: "yoshiki4",
      severity: "info",
      kind: "依頼",
      title: "持続化補助金の事業支援計画書（様式4）を商工会議所へ依頼",
      detail: "燕商工会議所への発行依頼が未着手。なお従業員数の要件は要確認です。",
      meta: "未着手",
    },
  ]

  return (
    <div className="mx-auto w-full max-w-5xl pb-16">
      <PageHeader
        title="補助金ナビ"
        subtitle="補助金・助成金マッチング"
        actions={
          <Badge variant="info" icon={<IconBuildingFactory2 />}>
            {company.name}
          </Badge>
        }
      />

      <div className="flex flex-col gap-6 px-4 pt-4">
        {/* ── 自社プロフィール ── */}
        <Card className="p-4">
          <div className="flex items-start gap-3">
            <div
              className="flex size-11 shrink-0 items-center justify-center rounded-lg bg-info-subtle"
              aria-hidden
            >
              <IconBuildingFactory2 className="size-6 text-info" />
            </div>
            <div className="min-w-0 flex-1">
              <div className="flex flex-wrap items-center gap-2">
                <h2 className="text-base font-semibold text-foreground">{company.name}</h2>
                <Badge variant="secondary">{company.industry}</Badge>
                <Badge
                  variant={company.gbizId === "取得済み" ? "success" : "warning"}
                  icon={<IconId />}
                >
                  gBizID {company.gbizId}
                </Badge>
              </div>
              <p className="mt-0.5 text-xs text-muted-foreground">{company.industryDetail}</p>
            </div>
          </div>
          <Separator className="my-3" />
          <MetadataList
            layout="horizontal"
            variant="compact"
            items={[
              { label: "業種", value: company.industry },
              { label: "従業員数", value: `${company.employees}名` },
              { label: "資本金", value: formatYenShort(company.capital) },
              { label: "売上高", value: formatYenShort(company.revenue) },
              { label: "所在地", value: company.location },
              { label: "創業", value: company.founded },
            ]}
          />
        </Card>

        {/* ── マッチKPI ── */}
        <section aria-label="マッチKPI">
          <StatGroup
            cols={{ base: 2, md: 4 }}
            items={[
              {
                label: "該当する補助金",
                value: `${kpis.matchedCount}件`,
                hint: "あなたの条件に合う制度",
              },
              {
                label: "申請可能",
                value: `${kpis.applicableCount}件`,
                hint: "適合度70%以上",
              },
              {
                label: "締切間近",
                value: `${kpis.deadlineSoonCount}件`,
                hint: "残り14日以内",
                tone: "negative",
              },
              {
                label: "推定受給額",
                value: formatYenShort(kpis.estimatedTotal),
                hint: "申請可能分の合計",
              },
            ]}
          />
        </section>

        {/* ── 絞り込み ── */}
        <section aria-label="絞り込み" className="flex flex-col gap-2">
          <span className="text-xs font-medium text-muted-foreground">補助金の種類</span>
          <FilterChips
            aria-label="補助金の種類で絞り込み"
            value={kind}
            onValueChange={(v) => setKind(v as KindFilter)}
            items={[
              { value: "all", label: "すべて", count: allPrograms.length },
              { value: "補助金", label: "補助金", count: allPrograms.filter((p) => p.kind === "補助金").length },
              { value: "助成金", label: "助成金", count: allPrograms.filter((p) => p.kind === "助成金").length },
            ]}
          />
          <span className="mt-1 text-xs font-medium text-muted-foreground">目的</span>
          <FilterChips
            aria-label="目的で絞り込み"
            value={purpose}
            onValueChange={(v) => setPurpose(v as PurposeFilter)}
            items={[
              { value: "all", label: "すべて" },
              { value: "設備投資", label: "設備投資" },
              { value: "IT", label: "IT" },
              { value: "人材", label: "人材" },
              { value: "販路開拓", label: "販路開拓" },
            ]}
          />
        </section>

        {/* ── おすすめ補助金ランキング ── */}
        <section aria-label="おすすめ補助金のランキング" className="flex flex-col gap-3">
          <div className="flex items-center gap-2">
            <IconTargetArrow className="size-5 text-primary" aria-hidden />
            <h2 className="text-base font-semibold text-foreground">適合度ランキング</h2>
            <span className="text-xs text-muted-foreground">おすすめ順 ({filtered.length}件)</span>
          </div>
          {leaderboardItems.length > 0 ? (
            <Card className="p-3">
              <Leaderboard
                label="適合度の高い補助金"
                items={leaderboardItems}
                max={100}
                showRank
                selectedId={selectedId}
                formatValue={(v) => `${v}%`}
              />
            </Card>
          ) : (
            <Card className="p-6 text-center text-sm text-muted-foreground">
              条件に合う補助金が見つかりませんでした。絞り込みを変更してください。
            </Card>
          )}
        </section>

        {/* ── マッチ詳細（自社 × 制度） ── */}
        <section aria-label="マッチの詳細" className="flex flex-col gap-3">
          <div className="flex items-center gap-2">
            <IconCircleCheck className="size-5 text-success" aria-hidden />
            <h2 className="text-base font-semibold text-foreground">マッチの詳細</h2>
          </div>
          <MatchDetail company={company} program={selected} />
        </section>

        {/* ── 要対応・締切 ── */}
        <section aria-label="要対応・締切" className="flex flex-col gap-3">
          <div className="flex items-center gap-2">
            <IconCalendarDue className="size-5 text-warning" aria-hidden />
            <h2 className="text-base font-semibold text-foreground">要対応・締切</h2>
          </div>
          <ActionQueue items={queueItems} />
        </section>
      </div>
    </div>
  )
}
